136			if report.Disrupted || isBudgetExhaustedFailure(report) || !policyescalation.ShouldEscalate(report.Status) || policyescalation.IsInfrastructureFailure(report.Status, report.Detail) {
137				return report, nil
138			}
139			basis := minPower
140			if report.ActualPower > 0 {
141				basis = report.ActualPower
142			}
143			nextPower, nextErr := nextEscalationFloor(ladder, basis)
144			if nextErr != nil {
145				return report, nil
146			}
147			minPower = nextPower
148		}
149	}
