170	func (m *WorkerManager) runWorker(ctx context.Context, id, dir string, spec ExecuteLoopWorkerSpec, projectRoot string, handle *workerHandle, log io.Writer, eventSink io.WriteCloser, progressCh chan agent.ProgressEvent) {
171		if eventSink != nil {
172			defer eventSink.Close() //nolint:errcheck
173		}
174		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
175		rcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
176			Assignee:          "ddx",
177			Harness:           spec.Harness,
178			Model:             spec.Model,
179			Provider:          spec.Provider,
180			ModelRef:          spec.ModelRef,
181			Profile:           agent.NormalizeRoutingProfile(spec.Profile),
182			Effort:            spec.Effort,
183			OpaquePassthrough: spec.OpaquePassthrough,
184		})
185	
186		var worker *agent.ExecuteBeadWorker
187		var costCap *policyescalation.CostCapTracker
188		if m.BeadWorkerFactory != nil {
189			worker = m.BeadWorkerFactory(store)
190		} else {
191			// Build an executor that calls agent.ExecuteBead in-process, then
192			// submits the result to the project's land coordinator. The
193			// coordinator (a single goroutine per projectRoot) serializes all
194			// target-ref writes for this project — this is the server-side
195			// implementation of the human-PR landing model. See ddx-8746d8a6
196			// for the rationale. Prior to this rewrite, runWorker never called
197			// LandBeadResult at all, so commits produced by server-managed
198			// workers were silently lost (ddx-e14efc58).
199			coordinator := m.LandCoordinators.Get(projectRoot)
200	
201			// singleTierAttempt runs one execution at a specific harness/model.
202			// The caller controls MinPower per rung; this helper keeps the
203			// profile stable and only advances the power floor.
204			singleTierAttempt := func(ctx context.Context, beadID string, requestedMinPower int, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
205				gitOps := &agent.RealGitOps{}
206				attemptProvider := spec.Provider
207				if resolvedProvider != "" {
208					attemptProvider = resolvedProvider
209				}
210				attemptRcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
211					Harness:           resolvedHarness,
212					Model:             resolvedModel,
213					Provider:          attemptProvider,
214					ModelRef:          spec.ModelRef,
215					Profile:           rcfg.Profile(),
216					Effort:            spec.Effort,
217					MinPower:          requestedMinPower,
218					OpaquePassthrough: spec.OpaquePassthrough,
219				})
220				beadStore := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
221				res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
222					BeadEvents: beadStore,
223					BeadCancel: beadStore,
224				}, gitOps)
225				if err != nil && res == nil {
226					return agent.ExecuteBeadReport{}, err
227				}
228				// Preserve operator-cancel results as-is; the worker has already
229				// classified them (preserved / operator_cancel / preserved_needs_review)
230				// and overriding here would lose the cancel signal.
231				operatorCancel := res != nil && res.Reason == agent.OperatorCancelReason
232				if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 && !operatorCancel {
233					if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, landSafetyConfigFromConfig(projectRoot), log); landErr != nil && err == nil {
234						err = landErr
235					}
236				} else if res != nil && res.ResultRev == res.BaseRev && !operatorCancel {
237					res.Outcome = "no-changes"
238					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
239				} else if res != nil && res.ExitCode != 0 && !operatorCancel {
240					res.Outcome = "preserved"

  1					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
  2				}
  3				// Safety net: commit any leftover evidence files that Land()
  4				// did not pick up (e.g. HEAD was detached, or no land ran).
  5				if res != nil && res.AttemptID != "" {
  6					_ = agent.VerifyCleanWorktree(projectRoot, res.AttemptID)
  7				}
  8				if err != nil {
  9					return agent.ExecuteBeadReport{}, err
 10				}
 11				return agent.ExecuteBeadReport{
 12					BeadID:             res.BeadID,
 13					AttemptID:          res.AttemptID,
 14					WorkerID:           res.WorkerID,
 15					Harness:            res.Harness,
 16					Provider:           res.Provider,
 17					Model:              res.Model,
 18					ActualPower:        res.ActualPower,
 19					Status:             res.Status,
 20					Detail:             res.Detail,
 21					SessionID:          res.SessionID,
 22					BaseRev:            res.BaseRev,
 23					ResultRev:          res.ResultRev,
 24					PreserveRef:        res.PreserveRef,
 25					NoChangesRationale: res.NoChangesRationale,
 26					CostUSD:            res.CostUSD,
 27					DurationMS:         int64(res.DurationMS),
 28				}, nil
 29			}
 30	
 31			// Cost-cap state for this worker run. Subscription / local providers do
 32			// not contribute (see escalation.CountsTowardCostCap).
 33			// TODO(ddx-785d02f7): expose maxCostUSD as a worker spec field
 34			// once the spec config knob lands.
 35			var ladderOnce sync.Once
 36			var ladder *tierescalation.Ladder
 37			loadLadder := func() *tierescalation.Ladder {
 38				ladderOnce.Do(func() {
 39					ladder = tierescalation.NewLadder(nil)
 40					if svc, svcErr := agent.NewServiceFromWorkDir(projectRoot); svcErr == nil {
 41						modelFilter := agentlib.ModelFilter{}
 42						if harness := rcfg.Harness(); harness != "" {
 43							modelFilter.Harness = harness
 44						}
 45						modelCtx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
 46						defer cancel()
 47						if models, listErr := svc.ListModels(modelCtx, modelFilter); listErr == nil {
 48							ladder = tierescalation.NewLadder(models)
 49						}
 50					}
 51				})
 52				return ladder
 53			}
 54			costCap = policyescalation.NewCostCapTracker(policyescalation.DefaultMaxCostUSD, func(harnessName string) bool {
 55				svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
 56				if svcErr != nil {
 57					return true
 58				}
 59				infos, err := svc.ListHarnesses(context.Background())
 60				if err != nil {
 61					return true
 62				}
 63				for _, h := range infos {
 64					if h.Name == harnessName {
 65						return policyescalation.CountsTowardCostCap(h.IsLocal, h.IsSubscription, h.CostClass)
 66					}
 67				}
 68				return true
 69			})
 70			accumulateBilledCost := func(report agent.ExecuteBeadReport) {
 71				costCap.Add(report.Harness, report.CostUSD)
 72			}
 73			costCapTripped := func() (agent.ExecuteBeadReport, bool) {
 74				if _, tripped := costCap.Tripped(); !tripped {
 75					return agent.ExecuteBeadReport{}, false
 76				}
 77				spent := costCap.Spent()
 78				return agent.ExecuteBeadReport{
 79					Status: agent.ExecuteBeadStatusExecutionFailed,
 80					Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, policyescalation.DefaultMaxCostUSD),
 81				}, true
 82			}
 83			attemptWithCostCap := func(ctx context.Context, beadID string, requestedMinPower int) (agent.ExecuteBeadReport, error) {
 84				if cappedReport, capped := costCapTripped(); capped {
 85					cappedReport.BeadID = beadID
 86					return cappedReport, nil
 87				}
 88				report, err := singleTierAttempt(ctx, beadID, requestedMinPower, spec.Harness, spec.Provider, spec.Model)
 89				if err == nil {
 90					accumulateBilledCost(report)
 91					if cappedReport, capped := costCapTripped(); capped {
 92						cappedReport.BeadID = beadID
 93						return cappedReport, nil
 94					}
 95				}
 96				return report, err
 97			}
 98	
 99			executor := agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
100				attempts := make([]policyescalation.TierAttemptRecord, 0, 3)
101				recordAttempt := func(report agent.ExecuteBeadReport) {
102					if report.Tier == "" && report.Harness == "" && report.Model == "" && report.ProbeResult == "" && report.CostUSD == 0 && report.DurationMS == 0 {
103						return
104					}
105					attempts = append(attempts, policyescalation.TierAttemptRecord{
106						Tier:       report.Tier,
107						Harness:    report.Harness,
108						Model:      report.Model,
109						Status:     report.Status,
110						CostUSD:    report.CostUSD,
111						DurationMS: report.DurationMS,
112					})
113					appendTierAttemptEvent(store, beadID, report, "ddx", time.Now().UTC())
114				}
115				report, err := runEscalatingSingleTierAttempts(ctx, rcfg.MinPower(), loadLadder(), func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
116					return attemptWithCostCap(ctx, beadID, requestedMinPower)
117				}, recordAttempt)
118				if len(attempts) > 0 {
119					winningTier := ""
120					if report.Status == agent.ExecuteBeadStatusSuccess && report.Tier != "" {
121						winningTier = report.Tier
122					}
123					_ = policyescalation.AppendEscalationSummaryEvent(store, beadID, "ddx", attempts, winningTier, time.Now().UTC())
124				}
125				return report, err
126			})
127	
128			// Build post-merge reviewer. On-by-default unless NoReview is set in spec.
129			var reviewer agent.BeadReviewer
130			if !spec.NoReview {
131				reviewer = &agent.DefaultBeadReviewer{
132					ProjectRoot: projectRoot,
133					BeadStore:   bead.NewStore(filepath.Join(projectRoot, ".ddx")),
134					BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
135					Harness:     spec.ReviewHarness,
136					Model:       spec.ReviewModel,
137				}
138			}
139	
140			worker = &agent.ExecuteBeadWorker{
141				Store:    store,
142				Executor: executor,
143				Reviewer: reviewer,
144			}
145		}
146	
147		landingOps := agent.RealLandingGitOps{}
148	
149		loopResult, err := worker.Run(ctx, rcfg, agent.ExecuteBeadLoopRuntime{
150			Once:          spec.Once,
151			PollInterval:  spec.PollInterval,
152			Log:           log,
153			EventSink:     eventSink,
154			WorkerID:      id,
155			ProjectRoot:   projectRoot,
156			LabelFilter:   spec.LabelFilter,
157			ProgressCh:    progressCh,
158			PreClaimHook:  buildPreClaimHook(projectRoot, landingOps),
159			NoReview:      spec.NoReview,
160			ReviewCostCap: costCap,
161			WakeCh:        handle.wakeCh,
162		})
163		// Signal end of progress events so drainProgress can finish
164		close(progressCh)
165		// Wait for drainProgress to process all remaining events (including live
166		// counter increments) before we overwrite handle.record with the final state.
167		<-handle.progressDone
168	
169		m.mu.Lock()
170		record := handle.record
171		// Preserve terminal state set by Stop() or the watchdog so the final
172		// writeRecord below does not overwrite "stopped" / "reaped" with
173		// "exited" / "failed".
174		preservedState := ""
175		if record.State == "stopped" || record.State == "reaped" {
176			preservedState = record.State
177		}
178		record.FinishedAt = time.Now().UTC()
179		// Terminal worker: clear any "idle" substate (ddx-dc157075 AC #5; substate
180		// is only meaningful while the worker is running).
181		record.Substate = ""
182		_ = handle.logFile.Close()
183	
184		if err != nil {
185			record.State = "failed"
186			record.Status = "failed"
187			record.Error = err.Error()
188			record.LastError = err.Error()
189		} else {
190			record.State = "exited"
191			record.Attempts = loopResult.Attempts
192			record.Successes = loopResult.Successes
193			record.Failures = loopResult.Failures
194	
195			if loopResult.NoReadyWork {
196				record.Status = "no_ready_work"
197			} else if loopResult.Failures > 0 && loopResult.Successes == 0 {
198				record.Status = "execution_failed"
199				if loopResult.LastFailureStatus != "" {
200					record.Status = loopResult.LastFailureStatus
201				}
202			} else if loopResult.Successes > 0 {
203				record.Status = "success"
204			} else {
205				record.Status = "exited"
206			}
207	
208			if len(loopResult.Results) > 0 {
209				last := loopResult.Results[len(loopResult.Results)-1]
210				r := WorkerExecutionResult{
211					BeadID:     last.BeadID,
212					AttemptID:  last.AttemptID,
213					WorkerID:   last.WorkerID,
214					Harness:    last.Harness,
215					Tier:       last.Tier,
216					Provider:   last.Provider,
217					Model:      last.Model,
218					Status:     last.Status,
219					Detail:     last.Detail,
220					SessionID:  last.SessionID,
221					BaseRev:    last.BaseRev,
222					ResultRev:  last.ResultRev,
223					RetryAfter: last.RetryAfter,
224				}
225				record.CurrentBead = last.BeadID
226				record.LastResult = &r
227				if last.Detail != "" {
228					record.LastError = last.Detail
229				}
230				if last.Harness != "" && record.Harness == "" {
231					record.Harness = last.Harness
232				}
233				if last.Model != "" && record.Model == "" {
234					record.Model = last.Model
235				}
236				if last.Provider != "" && record.Provider == "" {
237					record.Provider = last.Provider
238				}
239			}
240		}
241		// Terminal-state override: if Stop() or the watchdog already marked
242		// this worker, keep that label so external consumers see the reason.
243		if preservedState != "" {
244			record.State = preservedState
245			record.Status = preservedState
246		}
247		_ = m.writeRecord(dir, record)
248		handle.record = record
249		m.mu.Unlock()
250	}
